(function () {
    'use strict';

    /* DOM */
    var unlock = document.getElementById('unlock');
    var intro = document.getElementById('intro');
    var introX = document.getElementById('intro-x');
    var introFlash = document.querySelector('.intro-flash');
    var glitchBar = document.querySelector('.intro-glitch-bar');
    var page = document.getElementById('page');
    var music = document.getElementById('music');
    var heroVideo = document.querySelector('.bg-video');

    var btnRsvp = document.getElementById('btn-rsvp');
    var modal = document.getElementById('rsvp-modal');
    var modalFill = document.getElementById('modal-fill');
    var modalStatus = document.getElementById('modal-status');
    var modalInfo = document.getElementById('modal-info');
    var btnWa = document.getElementById('btn-wa');

    var waUrl = "https://api.whatsapp.com/send?phone=584145541300&text=%C2%A1Hola!%20Confirmo%20mi%20asistencia%20para%20Proyecto%20X.%20Aqu%C3%AD%20est%C3%A1%20mi%20pase%20de%20invitado.";
    var TICKET_B64 = "";

    document.body.classList.add('locked');

    /* ================================
       UNLOCK → INTRO
       ================================ */
    unlock.addEventListener('click', function () {
        /* Start music a bit ahead so the beat hits during intro */
        music.currentTime = 26;
        music.volume = 0;
        music.play().catch(function () {});
        if (heroVideo) heroVideo.play().catch(function () {});

        unlock.classList.add('out');
        setTimeout(function () {
            intro.classList.add('active');
            runIntro();
        }, 500);
    });

    /* ================================
       MUSIC
       ================================ */
    function fadeTo(vol, dur) {
        var s = music.volume, d = vol - s, n = 25, st = dur / n, c = 0;
        var iv = setInterval(function () {
            c++;
            music.volume = Math.min(Math.max(s + d * (c / n), 0), 1);
            if (c >= n) clearInterval(iv);
        }, st);
    }

    /* ================================
       FLASH & GLITCH
       ================================ */
    function flash() {
        introFlash.classList.remove('on');
        void introFlash.offsetWidth;
        introFlash.classList.add('on');
    }
    function sweep() {
        glitchBar.classList.remove('sweep');
        void glitchBar.offsetWidth;
        glitchBar.classList.add('sweep');
    }

    /* ================================
       INTRO: GLITCH X GROWING
       ================================ */
    function runIntro() {
        fadeTo(0.15, 300);

        /* Phase 1: small X appears */
        setTimeout(function () {
            introX.className = 'intro-x phase1';
            flash(); sweep();
            fadeTo(0.3, 400);
        }, 300);

        /* Phase 2: X gets bigger + glitch */
        setTimeout(function () {
            introX.className = 'intro-x phase2';
            flash(); sweep();
            fadeTo(0.5, 400);
        }, 900);

        /* Shake */
        setTimeout(function () {
            introX.className = 'intro-x phase2 shake';
            sweep();
        }, 1400);

        /* Phase 3: X fills screen */
        setTimeout(function () {
            introX.className = 'intro-x phase3';
            flash();
            fadeTo(0.75, 500);
        }, 1800);

        /* Final shake + flash */
        setTimeout(function () {
            introX.className = 'intro-x phase3 shake';
            flash();
        }, 2300);

        /* Explode X → reveal page */
        setTimeout(function () {
            introX.className = 'intro-x phase3 explode';
            flash();
            fadeTo(1.0, 1500);
        }, 2700);

        setTimeout(function () {
            intro.classList.add('out');
            page.classList.add('on');
            document.body.classList.remove('locked');
        }, 3100);
    }

    /* ================================
       SCROLL REVEAL
       ================================ */
    var els = document.querySelectorAll('.rv');
    function check() {
        for (var i = 0; i < els.length; i++) {
            if (els[i].getBoundingClientRect().top < window.innerHeight * 0.88) {
                els[i].classList.add('vis');
            }
        }
    }
    window.addEventListener('scroll', check, { passive: true });
    window.addEventListener('load', check);
    setTimeout(check, 200);

    /* ================================
       RSVP
       ================================ */
    function b64toBlob(b, m) {
        try {
            var bc = atob(b), bn = new Array(bc.length);
            for (var i = 0; i < bc.length; i++) bn[i] = bc.charCodeAt(i);
            return new Blob([new Uint8Array(bn)], { type: m });
        } catch (e) { return null; }
    }

    async function copyImg() {
        if (TICKET_B64 === "" || !TICKET_B64) return false;
        try {
            var bl = b64toBlob(TICKET_B64, 'image/jpeg');
            if (!bl) return false;
            await navigator.clipboard.write([new ClipboardItem({ 'image/jpeg': bl })]);
            return true;
        } catch (e) { return false; }
    }

    btnRsvp.addEventListener('click', function () {
        modal.classList.add('on');
        modalFill.style.width = '0%';
        modalStatus.innerText = 'Procesando...';
        modalInfo.classList.add('hidden');
        btnWa.classList.add('hidden');

        var p = 0;
        var iv = setInterval(async function () {
            p += 10;
            modalFill.style.width = p + '%';
            if (p === 30) modalStatus.innerText = 'Cargando pase...';
            else if (p === 70) modalStatus.innerText = 'Copiando imagen...';
            else if (p >= 100) {
                clearInterval(iv);
                var ok = await copyImg();
                if (ok) {
                    modalStatus.innerText = '¡PASE COPIADO!';
                    modalInfo.innerHTML =
                        '<p class="t">🎉 LISTO</p>' +
                        '<p>Tu <strong>pase (1.jpeg)</strong> fue copiado al portapapeles.</p>' +
                        '<p class="hl">En WhatsApp, mantén presionado y pega la imagen.</p>';
                } else {
                    modalStatus.innerText = 'COPIA NO DISPONIBLE';
                    modalInfo.innerHTML =
                        '<p class="t">📎 NOTA</p>' +
                        '<p>Adjunta <strong>1.jpeg</strong> desde tu galería al abrir WhatsApp.</p>';
                }
                modalInfo.classList.remove('hidden');
                btnWa.classList.remove('hidden');
                setTimeout(function () { window.open(waUrl, '_blank'); }, 3500);
            }
        }, 150);
    });

    btnWa.addEventListener('click', function () {
        window.open(waUrl, '_blank');
        modal.classList.remove('on');
    });

    modal.addEventListener('click', function (e) {
        if (e.target === modal) modal.classList.remove('on');
    });

})();
